import React from 'react'
 import "./popup.css";

function Popup(props){
  return (props.trigger)?(
    <div className='popup'>
        <div className='innerpopup'>
            <button className="close"> </button>
            {props.children}
                  My Popup
        </div>
      
    </div>
  ): ""
}

export default Popup
